  9→
 10→internal class TzFileData(
 11→    val leapSecondRules: List<LeapSecondRule>,
 12→    val transitions: List<Transition>,
 13→    val states: List<ClockState>,
 14→) {
 15→    /**
 16→     * The list of rules for inserting leap seconds.
 17→     */
 18→    class LeapSecondRule(
 19→        /**
 20→         * The time at which a new leap second is to be inserted.
 21→         */
 22→        val time: Long,
 23→        /**
 24→         * The total number of leap seconds to be applied after [time] and before the next rule.
 25→         */
 26→        val total: Int
 27→    )
 28→
 29→    class ClockState(
 30→        val offset: TzFileOffset,
 31→        val isDst: Boolean,
 32→        val abbreviation: String,
 33→    )
 34→
 35→    class Transition(
 36→        val time: Long,
 37→        val stateIndex: Int
 38→    )
 39→}
 40→
 41→internal class TzFile(val data: TzFileData, val rules: PosixTzString?) {
 42→    fun toTimeZoneRules(): TimeZoneRules {
 43→        val tzOffsets = buildList {
 44→            add(data.states[0].offset)
 45→            data.transitions.forEach { add(data.states[it.stateIndex].offset) }
 46→        }
 47→        val offsets = tzOffsets.map { it.toUtcOffset() }
 48→        return TimeZoneRules(data.transitions.map { it.time }, offsets, rules?.toRecurringZoneRules())
 49→    }
 50→}
 51→
 52→/**
 53→ * An extension of [UtcOffset] to support the full range of offsets used in `tzfile`, which is:
 54→ *
 55→ * ```
 56→ * The tt_utoff value is never equal to -2**31, to let 32-bit clients negate it without overflow.
 57→ * Also, in realistic applications tt_utoff is in the range [-89999, 93599] (i.e., more than -25 hours and less than 26
 58→ * hours); this allows easy support by implementations that already support the POSIX-required range
 59→ * [-24:59:59, 25:59:59].
 60→ * ```
 61→ */
 62→internal class TzFileOffset(val totalSeconds: Int) {
 63→    /**
 64→     * Converts this offset to a [UtcOffset].
 65→     *
 66→     * @throws IllegalArgumentException if the offset is not in the range [-18 hours, +18 hours].
 67→     */
 68→    fun toUtcOffset(): UtcOffset = UtcOffset(seconds = totalSeconds)
 69→}
 70→
 71→// https://datatracker.ietf.org/doc/html/rfc8536
 72→internal fun readTzFile(data: ByteArray): TzFile {
 73→    class Header(
 74→        val version: Int?,
 75→        val ttisutcnt: Int,
 76→        val ttisstdcnt: Int,
 77→        val leapcnt: Int,
 78→        val timecnt: Int,
 79→        val typecnt: Int,
 80→        val charcnt: Int
 81→    ) {
 82→        override fun toString(): String = "Header(version=$version, ttisutcnt=$ttisutcnt, ttisstdcnt=$ttisstdcnt, " +
 83→            "leapcnt=$leapcnt, timecnt=$timecnt, typecnt=$typecnt, charcnt=$charcnt)"
 84→    }
 85→
 86→    class Ttinfo(val utoff: Int, val isdst: Boolean, val abbrind: UByte) {
 87→        override fun toString(): String = "Ttinfo(utoff=$utoff, isdst=$isdst, abbrind=$abbrind)"
 88→    }
 89→
 90→    inline fun BinaryDataReader.readData(header: Header, readTime: () -> Long): TzFileData {
 91→        val transitionTimes = List(header.timecnt) { readTime() }
 92→        val transitionTypes = List(header.timecnt) { readByte() }
 93→        val ttinfos = List(header.typecnt) {
 94→            Ttinfo(
 95→                readInt(),
 96→                readByte() != 0.toByte(),
 97→                readUnsignedByte()
 98→            )
 99→        }
100→        val abbreviations = List(header.charcnt) { readByte() }
101→        fun abbreviationForIndex(startIndex: UByte): String = abbreviations.drop(startIndex.toInt())
102→            .takeWhile { byte -> byte != 0.toByte() }.toByteArray().decodeToString()
103→        val leapSecondRules = List(header.leapcnt) {
104→            TzFileData.LeapSecondRule(
105→                readTime(),
106→                readInt()
107→            )
108→        }
109→        // The following fields are not used in practice. See https://datatracker.ietf.org/doc/html/rfc8536#section-3.2,
110→        // near the end of the section, `A given pair of standard/wall and UT/local indicators...`
111→        repeat(header.ttisstdcnt) { readByte() }
112→        repeat(header.ttisutcnt) { readByte() }
113→        return TzFileData(
114→            leapSecondRules,
115→            transitionTimes.zip(transitionTypes) { time, type -> TzFileData.Transition(time, type.toInt()) },
116→            ttinfos.map { TzFileData.ClockState(TzFileOffset(it.utoff), it.isdst, abbreviationForIndex(it.abbrind)) }
117→        )
118→    }
119→
120→    fun BinaryDataReader.read32BitData(header: Header): TzFileData = readData(header) { readInt().toLong() }
121→
122→    fun BinaryDataReader.read64BitData(header: Header): TzFileData = readData(header) { readLong() }
123→
124→    inline fun BinaryDataReader.readFooter() = check(readByte() == '\n'.code.toByte()).let {
125→        PosixTzString.readIfPresent(this)
126→    }
127→
128→    val reader = BinaryDataReader(data)
129→
130→    fun readHeader(): Header {
131→        val magic = reader.readUtf8String(4)
132→        check(magic == "TZif") { "Invalid tzfile magic: '$magic', expected 'TZif'" }
133→        val version = when (reader.readByte()) {
134→            0.toByte() -> 1
135→            0x32.toByte() -> 2
136→            0x33.toByte() -> 3
137→            else -> null
138→        }
139→        reader.skip(15)
140→        return Header(
141→            version,
142→            reader.readInt(),
143→            reader.readInt(),
144→            reader.readInt(),
145→            reader.readInt(),
146→            reader.readInt(),
147→            reader.readInt()
148→        ).also {
149→            check(it.ttisutcnt == 0 || it.ttisutcnt == it.typecnt)
150→            check(it.ttisstdcnt == 0 || it.ttisstdcnt == it.typecnt)
151→        }
152→    }
153→
154→    val header = readHeader()
155→    return when (header.version) {
156→        1 -> {
157→            TzFile(reader.read32BitData(header), null)
158→        }
159→        else -> {
160→            reader.read32BitData(header) // skipped
161→            val newHeader = readHeader()
162→            val parsedData = reader.read64BitData(newHeader)
163→            val footer = reader.readFooter()
164→            TzFile(parsedData, footer)
165→        }
166→    }
167→}
168→
169→internal class PosixTzString(
170→    private val standardTime: Pair<String, UtcOffset>,
171→    private val daylightTime: Pair<String, UtcOffset>?,
172→    private val rules: Pair<MonthDayTime, MonthDayTime>?,
173→) {
174→    companion object {
175→        /**
176→         * Reads a POSIX TZ string from the [reader] if it is present, or returns `null` if it is not.
177→         *
178→         * The string format is described in https://pubs.opengroup.org/onlinepubs/9699919799/, section 8.3,
179→         * with additional extensions in https://datatracker.ietf.org/doc/html/rfc8536#section-3.3.1
180→         *
181→         * @throws IllegalArgumentException if the string is invalid
182→         * @throws IllegalStateException if the string is invalid
183→         */
184→        fun readIfPresent(reader: BinaryDataReader): PosixTzString? = reader.readPosixTzString()
185→    }
186→
187→    fun toRecurringZoneRules(): RecurringZoneRules? {
188→        /**
189→         * In theory, it's possible to have a DST transition but no start/end date.
190→         * In this case, the behavior is not specified, and on Linux, the rules for America/New_York are used
191→         * to determine the start/end dates (see `tzset(3)`, search for `posixrules`).
192→         * The <https://github.com/HowardHinnant/date> library takes the lack of start/end dates
193→         * to mean that the standard offset is always in effect, which seems to be a much more reasonable interpretation.
194→         */
195→        if (daylightTime == null || rules == null) return null
196→        val (start, end) = rules
197→        val rule1 = RecurringZoneRules.Rule(start, standardTime.second, daylightTime.second)
198→        val rule2 = RecurringZoneRules.Rule(end, daylightTime.second, standardTime.second)
199→        return RecurringZoneRules(listOf(rule1, rule2))
200→    }
201→}
202→private fun BinaryDataReader.readPosixTzString(): PosixTzString? {
203→    var c = readAsciiChar()
204→    fun readName(): String? {
205→        if (c == '\n') return null
