 52→/**
 53→ * An extension of [UtcOffset] to support the full range of offsets used in `tzfile`, which is:
 54→ *
 55→ * ```
 56→ * The tt_utoff value is never equal to -2**31, to let 32-bit clients negate it without overflow.
 57→ * Also, in realistic applications tt_utoff is in the range [-89999, 93599] (i.e., more than -25 hours and less than 26
 58→ * hours); this allows easy support by implementations that already support the POSIX-required range
 59→ * [-24:59:59, 25:59:59].
 60→ * ```
 61→ */
 62→internal class TzFileOffset(val totalSeconds: Int) {
 63→    /**
 64→     * Converts this offset to a [UtcOffset].
 65→     *
 66→     * @throws IllegalArgumentException if the offset is not in the range [-18 hours, +18 hours].
 67→     */
 68→    fun toUtcOffset(): UtcOffset = UtcOffset(seconds = totalSeconds)
 69→}
