 71→// https://datatracker.ietf.org/doc/html/rfc8536
 72→internal fun readTzFile(data: ByteArray): TzFile {
 73→    class Header(
 74→        val version: Int?,
 75→        val ttisutcnt: Int,
 76→        val ttisstdcnt: Int,
 77→        val leapcnt: Int,
 78→        val timecnt: Int,
 79→        val typecnt: Int,
 80→        val charcnt: Int
 81→    ) {
 82→        override fun toString(): String = "Header(version=$version, ttisutcnt=$ttisutcnt, ttisstdcnt=$ttisstdcnt, " +
 83→            "leapcnt=$leapcnt, timecnt=$timecnt, typecnt=$typecnt, charcnt=$charcnt)"
 84→    }
 85→
 86→    class Ttinfo(val utoff: Int, val isdst: Boolean, val abbrind: UByte) {
 87→        override fun toString(): String = "Ttinfo(utoff=$utoff, isdst=$isdst, abbrind=$abbrind)"
 88→    }
 89→
 90→    inline fun BinaryDataReader.readData(header: Header, readTime: () -> Long): TzFileData {
 91→        val transitionTimes = List(header.timecnt) { readTime() }
 92→        val transitionTypes = List(header.timecnt) { readByte() }
 93→        val ttinfos = List(header.typecnt) {
 94→            Ttinfo(
 95→                readInt(),
 96→                readByte() != 0.toByte(),
 97→                readUnsignedByte()
 98→            )
 99→        }
100→        val abbreviations = List(header.charcnt) { readByte() }
101→        fun abbreviationForIndex(startIndex: UByte): String = abbreviations.drop(startIndex.toInt())
102→            .takeWhile { byte -> byte != 0.toByte() }.toByteArray().decodeToString()
103→        val leapSecondRules = List(header.leapcnt) {
104→            TzFileData.LeapSecondRule(
105→                readTime(),
106→                readInt()
107→            )
108→        }
109→        // The following fields are not used in practice. See https://datatracker.ietf.org/doc/html/rfc8536#section-3.2,
110→        // near the end of the section, `A given pair of standard/wall and UT/local indicators...`
111→        repeat(header.ttisstdcnt) { readByte() }
112→        repeat(header.ttisutcnt) { readByte() }
113→        return TzFileData(
114→            leapSecondRules,
115→            transitionTimes.zip(transitionTypes) { time, type -> TzFileData.Transition(time, type.toInt()) },
116→            ttinfos.map { TzFileData.ClockState(TzFileOffset(it.utoff), it.isdst, abbreviationForIndex(it.abbrind)) }
117→        )
118→    }
119→
120→    fun BinaryDataReader.read32BitData(header: Header): TzFileData = readData(header) { readInt().toLong() }
121→
122→    fun BinaryDataReader.read64BitData(header: Header): TzFileData = readData(header) { readLong() }
123→
124→    inline fun BinaryDataReader.readFooter() = check(readByte() == '\n'.code.toByte()).let {
125→        PosixTzString.readIfPresent(this)
126→    }
127→
128→    val reader = BinaryDataReader(data)
129→
130→    fun readHeader(): Header {
131→        val magic = reader.readUtf8String(4)
132→        check(magic == "TZif") { "Invalid tzfile magic: '$magic', expected 'TZif'" }
133→        val version = when (reader.readByte()) {
134→            0.toByte() -> 1
135→            0x32.toByte() -> 2
136→            0x33.toByte() -> 3
137→            else -> null
138→        }
139→        reader.skip(15)
140→        return Header(
141→            version,
142→            reader.readInt(),
143→            reader.readInt(),
144→            reader.readInt(),
145→            reader.readInt(),
146→            reader.readInt(),
147→            reader.readInt()
148→        ).also {
149→            check(it.ttisutcnt == 0 || it.ttisutcnt == it.typecnt)
150→            check(it.ttisstdcnt == 0 || it.ttisstdcnt == it.typecnt)
151→        }
152→    }
153→
154→    val header = readHeader()
155→    return when (header.version) {
156→        1 -> {
157→            TzFile(reader.read32BitData(header), null)
158→        }
159→        else -> {
160→            reader.read32BitData(header) // skipped
161→            val newHeader = readHeader()
162→            val parsedData = reader.read64BitData(newHeader)
163→            val footer = reader.readFooter()
164→            TzFile(parsedData, footer)
165→        }
166→    }
167→}
